SELECT player_id, wins
FROM player_game_modes
WHERE wins > 5;

SELECT game_mode_name, max_players
FROM game_modes
ORDER BY max_players DESC;

SELECT AVG(score) AS average_score
FROM player_game_modes
WHERE game_mode_id = 1;

SELECT AVG(stat_value) AS average_score
FROM game_mode_stats
WHERE game_mode_id = 1 AND stat_name = 'Average Score';
